parameters.jsCode:
const data = $json;

// -----------------------------
// Metadata (STRICT – Only Requested Fields)
// -----------------------------
const metadata = {
  "@timestamp": data["@timestamp"] ?? null,
  incident_id: data.incident_id ?? null,
  severity: data.severity ?? null,
  category: data.category ?? null,
  type: data.type ?? null,

  affected_systems: Array.isArray(data.affected_systems)
    ? data.affected_systems
    : [],

  mitre_tactic_ids: Array.isArray(data.mitre_tactic_ids)
    ? data.mitre_tactic_ids
    : [],

  mitre_technique_ids: Array.isArray(data.mitre_technique_ids)
    ? data.mitre_technique_ids
    : [],

  mitre_prevention_ids: Array.isArray(data.mitre_prevention_ids)
    ? data.mitre_prevention_ids
    : [],

  // ✅ New fields retained
  description: data.description ?? null,
  alert_source: data.alert_source ?? null,
  rule_name: data.rule_name ?? null,
  entities: typeof data.entities === 'object' ? data.entities : {},
  detection_gap: data.detection_gap ?? null,
  what_went_well: Array.isArray(data.what_went_well) ? data.what_went_well : [],
  what_went_wrong: Array.isArray(data.what_went_wrong) ? data.what_went_wrong : []
};

// Remove null/undefined only
Object.keys(metadata).forEach(key => {
  if (metadata[key] === undefined || metadata[key] === null) {
    delete metadata[key];
  }
});

// -----------------------------
// Markdown Content
// -----------------------------
const sections = [];

// Header
sections.push(`# Incident: ${data.title ?? "Untitled Incident"}`);
sections.push(`**Incident ID:** ${data.incident_id ?? "N/A"}`);
sections.push(`**Severity:** ${data.severity ?? "N/A"}`);
sections.push(`**Category:** ${data.category ?? "N/A"}`);
sections.push(`**Type:** ${data.type ?? "N/A"}`);
sections.push(`**Status:** ${data.status ?? "N/A"}`);
sections.push(`**Date:** ${data["@timestamp"] ?? "N/A"}`);

if (Array.isArray(data.affected_systems) && data.affected_systems.length > 0) {
  sections.push(`**Affected Systems:** ${data.affected_systems.join(", ")}`);
}

// Alert Source
if (data.alert_source) {
  sections.push("");
  sections.push("## Alert Source");
  sections.push(`**Detection Tool:** ${data.alert_source}`);
  if (data.rule_name) {
    sections.push(`**Rule/Finding:** ${data.rule_name}`);
  }
}

// Entities (clean + safe)
const entities = metadata.entities;

if (
  entities &&
  typeof entities === 'object' &&
  Object.keys(entities).length > 0
) {
  const entityLines = [];

  if (Array.isArray(entities.users) && entities.users.length > 0)
    entityLines.push(`**Users:** ${entities.users.join(', ')}`);

  if (Array.isArray(entities.ips) && entities.ips.length > 0)
    entityLines.push(`**IPs:** ${entities.ips.join(', ')}`);

  if (Array.isArray(entities.hosts) && entities.hosts.length > 0)
    entityLines.push(`**Hosts:** ${entities.hosts.join(', ')}`);

  if (Array.isArray(entities.domains) && entities.domains.length > 0)
    entityLines.push(`**Domains:** ${entities.domains.join(', ')}`);

  if (Array.isArray(entities.hashes) && entities.hashes.length > 0)
    entityLines.push(`**Hashes:** ${entities.hashes.join(', ')}`);

  if (entityLines.length > 0) {
    sections.push("");
    sections.push("## Entities");
    entityLines.forEach(l => sections.push(l));
  }
}

// Description
if (data.description) {
  sections.push("");
  sections.push("## Description");
  sections.push(data.description);
}

// Detection Gap
if (data.detection_gap) {
  sections.push("");
  sections.push("## Detection Gap");
  sections.push(data.detection_gap);
}

// Timeline (safe)
if (Array.isArray(data.timeline) && data.timeline.length > 0) {
  sections.push("");
  sections.push("## Timeline");

  data.timeline.slice(0, 50).forEach(t => {
    if (t && t.timestamp && t.event) {
      sections.push(`- ${t.timestamp} — ${t.event}`);
    }
  });
}

// Root Cause
if (data.root_cause_analysis) {
  sections.push("");
  sections.push("## Root Cause");
  sections.push(data.root_cause_analysis);
}

// What Went Well
if (Array.isArray(data.what_went_well) && data.what_went_well.length > 0) {
  sections.push("");
  sections.push("## What Went Well");
  data.what_went_well.forEach(item => sections.push(`- ${item}`));
}

// What Went Wrong
if (Array.isArray(data.what_went_wrong) && data.what_went_wrong.length > 0) {
  sections.push("");
  sections.push("## What Went Wrong");
  data.what_went_wrong.forEach(item => sections.push(`- ${item}`));
}

// Resolution Summary
if (data.resolution_summary) {
  sections.push("");
  sections.push("## Resolution Summary");
  sections.push(data.resolution_summary);
}

// Remediation Actions
if (Array.isArray(data.remediation_actions) && data.remediation_actions.length > 0) {
  sections.push("");
  sections.push("## Remediation Actions");
  data.remediation_actions.forEach(action => {
    sections.push(`- ${action}`);
  });
}

// Lessons Learned
if (data.lessons_learned) {
  sections.push("");
  sections.push("## Lessons Learned");
  sections.push(data.lessons_learned);
}

// MITRE Mapping (safe)
const mitre = [];

if (Array.isArray(metadata.mitre_tactic_ids) && metadata.mitre_tactic_ids.length > 0)
  mitre.push(`Tactics: ${metadata.mitre_tactic_ids.join(", ")}`);

if (Array.isArray(metadata.mitre_technique_ids) && metadata.mitre_technique_ids.length > 0)
  mitre.push(`Techniques: ${metadata.mitre_technique_ids.join(", ")}`);

if (Array.isArray(metadata.mitre_prevention_ids) && metadata.mitre_prevention_ids.length > 0)
  mitre.push(`Prevention: ${metadata.mitre_prevention_ids.join(", ")}`);

if (mitre.length > 0) {
  sections.push("");
  sections.push("## MITRE Mapping");
  sections.push(mitre.join("\n"));
}

// Final Output
const pageContent = sections.join("\n");

return {
  json: {
    pageContent,
    metadata
  }
};

