{
  "type": "object",
  "properties": {
    "incident_summary": {
      "type": "string",
      "description": "3–5 sentence summary: what happened, severity, single most important action."
    },
    "similar_past_incidents_used": {
      "type": "array",
      "description": "incident_id values from past_incident_data that materially influenced this response.",
      "items": { "type": "string" }
    },
    "immediate_actions": {
      "type": "array",
      "description": "Each action from the IMMEDIATE (0–15 min) block of Section 5, as individual strings.",
      "items": { "type": "string" },
      "minItems": 1
    },
    "containment_guidance": {
      "type": "array",
      "description": "Each action from the CONTAINMENT (15–60 min) block of Section 5, as individual strings.",
      "items": { "type": "string" }
    },
    "iocs_extracted": {
      "type": "array",
      "description": "IOC values extracted from Section 4 — IPs, hashes, domains, process names. Empty array if none.",
      "items": { "type": "string" }
    },
    "assumptions_and_confidence": {
      "type": "object",
      "properties": {
        "confidence_level": {
          "type": "string",
          "enum": ["high", "medium", "low"]
        },
        "generic_playbook_used": {
          "type": "boolean",
          "description": "true if GEN-UNIVERSAL-001 playbook was used."
        },
        "caveat_notes": {
          "type": "array",
          "items": { "type": "string" }
        }
      },
      "required": ["confidence_level", "generic_playbook_used", "caveat_notes"],
      "additionalProperties": false
    },
    "report_markdown": {
      "type": "string",
      "description": "The complete, fully formatted 11-section Markdown IR report. Must not be empty or truncated."
    }
  },
  "required": [
    "incident_summary",
    "immediate_actions",
    "containment_guidance",
    "iocs_extracted",
    "assumptions_and_confidence",
    "report_markdown"
  ],
  "additionalProperties": false
}
